#include <bits/stdc++.h>
#define int long long
using namespace std;
#define MAX 100005
#define MOD 1000000007
void add (int &x, int y) {
	x += y;
	if (x >= MOD) {
		x -= MOD;
	}
	return;
}
struct Line {
	int v, Next;
};
Line e[MAX << 1];
int h[MAX], cnt = 1;
void Add (int u, int v) {
	e[cnt] = (Line){v, h[u]};
	h[u] = cnt++;
}
int n, K;
int f[MAX][101][2][2];
int size[MAX];
int tmp[101][2][2];
void dfs (int u, int ff) {
	size[u] = 1;
	f[u][0][0][0] = 1;
	f[u][1][1][0] = 1;
	for (int i = h[u]; i; i = e[i].Next) {
		int v = e[i].v;
		if (v == ff) {
			continue;
		}
		dfs (v, u);
		for (int j = 0; j <= size[u] && j <= K; j++) {
			for (int k = 0; k <= size[v] && j + k <= K; k++) {
				if (f[u][j][0][0]) {
					add (tmp[j + k][0][0], f[u][j][0][0] * f[v][k][0][1] % MOD);
					add (tmp[j + k][0][1], f[u][j][0][0] * f[v][k][1][1] % MOD);
				}
				if (f[u][j][0][1]) {
					add (tmp[j + k][0][1], f[u][j][0][1] * (f[v][k][0][1] + f[v][k][1][1]) % MOD);
				}
				if (f[u][j][1][0]) {
					add (tmp[j + k][1][0], f[u][j][1][0] * (f[v][k][0][0] + f[v][k][0][1]) % MOD);
					add (tmp[j + k][1][1], f[u][j][1][0] * (f[v][k][1][0] + f[v][k][1][1]) % MOD);
				}
				if (f[u][j][1][1]) {
					int s = 0;
					add (s, f[v][k][0][0]);
					add (s, f[v][k][0][1]);
					add (s, f[v][k][1][0]);
					add (s, f[v][k][1][1]);
					add (tmp[j + k][1][1], f[u][j][1][1] * s % MOD);
				}
			}
		}
		size[u] += size[v];
		for (int j = 0; j <= size[u] && j <= K; ++j) {
			f[u][j][0][0] = tmp[j][0][0];
			tmp[j][0][0] = 0;
			f[u][j][0][1] = tmp[j][0][1];
			tmp[j][0][1] = 0;
			f[u][j][1][0] = tmp[j][1][0];
			tmp[j][1][0] = 0;
			f[u][j][1][1] = tmp[j][1][1];
			tmp[j][1][1] = 0;
		}
	}
}
signed main() {
	ios::sync_with_stdio (0);
	cin.tie (0), cout.tie (0);
	cin >> n >> K;
	for (int i = 1, u, v; i < n; i++) {
		cin >> u >> v;
		Add (u, v);
		Add (v, u);
	}
	dfs (1, 0);
	int ans = (f[1][K][0][1] + f[1][K][1][1]) % MOD;
	cout << ans;
	return 0;
}
